import re
from collections import Counter

SCHEMA_PROMPTS = {
    'decompose': "Break the problem into short subcomputations, update quantities step by step, then give the final answer.",
    'evidence': "List the key facts, combine them carefully, then give the final answer.",
    'elimination': "Consider the options, eliminate wrong ones one by one, then give the final answer.",
    'subgoal_verify': "State a subgoal, solve it, verify the result briefly, then give the final answer."
}

SCHEMA_COMPAT = {
    'arithmetic': {'decompose': 1.0, 'subgoal_verify': 0.8, 'evidence': 0.3, 'elimination': 0.2},
    'boolean': {'evidence': 1.0, 'subgoal_verify': 0.7, 'decompose': 0.3, 'elimination': 0.2},
    'multichoice': {'elimination': 1.0, 'evidence': 0.6, 'subgoal_verify': 0.5, 'decompose': 0.3},
    'other': {'subgoal_verify': 0.7, 'evidence': 0.5, 'decompose': 0.5, 'elimination': 0.4}
}

def infer_qtype(question: str):
    q = question.lower()
    if re.search(r'\b(a\)|b\)|c\)|d\)|option|choices?)\b', q):
        return 'multichoice'
    if q.startswith('yes') or q.startswith('no') or ' yes or no' in q or q.startswith('is ') or q.startswith('are '):
        return 'boolean'
    if any(tok in q for tok in ['how many', 'how much', 'total', 'left', '+', '-', 'times', 'each']):
        return 'arithmetic'
    return 'other'

def extract_answer(text: str):
    m = re.search(r'(final answer\s*[:\-]?\s*)(.+)$', text, re.I | re.M)
    return m.group(2).strip() if m else ''

def answer_consistency(text: str):
    ans = extract_answer(text)
    if not ans:
        return 0.0
    body = re.sub(r'final answer\s*[:\-]?.*$', '', text, flags=re.I | re.M).lower()
    return 1.0 if ans.lower() in body else 0.4

def progression_score(text: str):
    t = text.lower()
    numbered = len(re.findall(r'(^|\n)\s*(\d+\.|-)\s+', text))
    updates = len(re.findall(r'(=|therefore|so |then |remaining|total|now)', t))
    return min(1.0, 0.15 * numbered + 0.12 * updates)

def brevity_score(text: str, target=90):
    n = len(text.split())
    return max(0.0, 1.0 - max(0, n - target) / target)

def schema_fit(question: str, schema: str):
    qtype = infer_qtype(question)
    return SCHEMA_COMPAT[qtype][schema]

def score_candidate(question: str, schema: str, rationale: str,
                    w1=0.35, w2=0.25, w3=0.30, w4=0.10):
    return (w1 * answer_consistency(rationale) +
            w2 * progression_score(rationale) +
            w3 * schema_fit(question, schema) +
            w4 * brevity_score(rationale))

def generate_schema_candidates(question, llm_generate):
    cands = []
    for schema, inst in SCHEMA_PROMPTS.items():
        prompt = f"Q: {question}\nA: {inst}"
        rat = llm_generate(prompt)
        s = score_candidate(question, schema, rat)
        cands.append({'schema': schema, 'rationale': rat, 'score': s})
    return cands

def select_complementary_demos(questions, llm_generate, lambda_dup=0.15):
    selected, used = [], Counter()
    for q in questions:
        cands = generate_schema_candidates(q, llm_generate)
        best = max(cands, key=lambda x: x['score'] - lambda_dup * used[x['schema']])
        used[best['schema']] += 1
        selected.append((q, best['schema'], best['rationale']))
    return selected

